 442→        if(hasLiked.error || hasBookMarked.error){
 443→            console.error('error', hasLiked.error || hasBookMarked.error)
 444→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
 445→        }
 446→        hasLikedResult = hasLiked.data || [];
 447→        hasBookMarkedResult = hasBookMarked.data || [];
 448→    }
 449→
 450→    const userHasLikedSet = new Set(hasLikedResult.map((like) => like.journal_id));
 451→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id));
 452→
 453→    const formatted = merged.map((notification) =>({
 454→        ...notification,
 455→        hasLiked: notification.source === 'journal' ? userHasLikedSet.has(notification?.journal_id) : false,
 456→        hasBookMarked: notification.source === 'journal' ? userHasBookmarkedSet.has(notification?.journal_id) : false
 457→    }))
 458→
 459→    const hasMore = formatted.length > parsedLimit;
