  35→const attachRepostSources = async (journals) => {
  36→    const items = Array.isArray(journals) ? journals : [journals];
  37→    const sourceIds = [...new Set(
  38→        items
  39→            .filter(j => j.is_repost === true && j.repost_source_journal_id != null)
  40→            .map(j => j.repost_source_journal_id)
  41→    )];
  42→
  43→    if (sourceIds.length === 0) {
  44→        items.forEach(j => { j.repost_source = null; });
  45→        return journals;
  46→    }
  47→
  48→    const { data: sources, error } = await supabase
  49→        .from('journals')
  50→        .select('id, title, content, post_type, canvas_doc, created_at, users(id, name, image_url, badge)')
  51→        .in('id', sourceIds);
  52→
  53→    if (error) {
  54→        console.error('supabase error fetching repost sources:', error.message);
  55→        items.forEach(j => { j.repost_source = null; });
  56→        return journals;
  57→    }
  58→
  59→    const sourceMap = new Map(sources.map(s => [s.id, s]));
  60→    items.forEach(j => {
  61→        j.repost_source = j.repost_source_journal_id
  62→            ? (sourceMap.get(j.repost_source_journal_id) || null)
  63→            : null;
  64→    });
  65→
  66→    return journals;
  67→};
