 475→const hydrateMediaItems = async(items) => {
 476→    if(!Array.isArray(items) || items.length === 0){
 477→        return [];
 478→    }
 479→
 480→    const hydrated = await Promise.all(items.map(async(item) => {
 481→        const url = await resolveMediaUrl(item.bucket, item.path);
 482→        if(!url){
 483→            return null;
 484→        }
 485→
 486→        return {
 487→            id: `${item.bucket}-${item.path}`,
 488→            bucket: item.bucket,
 489→            path: item.path,
 490→            name: item.name,
 491→            createdAt: item.createdAt || null,
 492→            timestamp: item.timestamp || 0,
 493→            url: url
 494→        };
 495→    }));
 496→
 497→    return hydrated.filter(Boolean);
 498→};
